#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeVeloHandle: FfiConverter {

    typealias FfiType = UnsafeMutableRawPointer
    typealias SwiftType = VeloHandle

    public static func lift(_ pointer: UnsafeMutableRawPointer) throws -> VeloHandle {
        return VeloHandle(unsafeFromRawPointer: pointer)
    }

    public static func lower(_ value: VeloHandle) -> UnsafeMutableRawPointer {
        return value.uniffiClonePointer()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> VeloHandle {
        let v: UInt64 = try readInt(&buf)
        // The Rust code won't compile if a pointer won't fit in a UInt64.
        // We have to go via `UInt` because that's the thing that's the size of a pointer.
        let ptr = UnsafeMutableRawPointer(bitPattern: UInt(truncatingIfNeeded: v))
        if (ptr == nil) {
            throw UniffiInternalError.unexpectedNullPointer
        }
        return try lift(ptr!)
    }

    public static func write(_ value: VeloHandle, into buf: inout [UInt8]) {
        // This fiddling is because `Int` is the thing that's the same size as a pointer.
        // The Rust code won't compile if a pointer won't fit in a `UInt64`.
        writeInt(&buf, UInt64(bitPattern: Int64(Int(bitPattern: lower(value)))))
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeVeloHandle_lift(_ pointer: UnsafeMutableRawPointer) throws -> VeloHandle {
    return try FfiConverterTypeVeloHandle.lift(pointer)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeVeloHandle_lower(_ value: VeloHandle) -> UnsafeMutableRawPointer {
    return FfiConverterTypeVeloHandle.lower(value)
}




public struct BikeInfoDto {
    public var bikeId: String
    public var name: String

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(bikeId: String, name: String) {
        self.bikeId = bikeId
        self.name = name
    }
}

#if compiler(>=6)
extension BikeInfoDto: Sendable {}
#endif


extension BikeInfoDto: Equatable, Hashable {
    public static func ==(lhs: BikeInfoDto, rhs: BikeInfoDto) -> Bool {
        if lhs.bikeId != rhs.bikeId {
            return false
        }
        if lhs.name != rhs.name {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(bikeId)
        hasher.combine(name)
    }
}



