/**
 * Shell uploads FIT + optional screenshot (Strava OAuth) or saves locally.
 */
public protocol ActivityPublisherCallback: AnyObject, Sendable {
    
    func publishRide(fitBytes: Data, screenshotPng: Data?, summary: RideSummaryDto)  -> PublishResultDto
    
}


// Put the implementation in a struct so we don't pollute the top-level namespace
fileprivate struct UniffiCallbackInterfaceActivityPublisherCallback {

    // Create the VTable using a series of closures.
    // Swift automatically converts these into C callback functions.
    //
    // This creates 1-element array, since this seems to be the only way to construct a const
    // pointer that we can pass to the Rust code.
    static let vtable: [UniffiVTableCallbackInterfaceActivityPublisherCallback] = [UniffiVTableCallbackInterfaceActivityPublisherCallback(
        publishRide: { (
            uniffiHandle: UInt64,
            fitBytes: RustBuffer,
            screenshotPng: RustBuffer,
            summary: RustBuffer,
            uniffiOutReturn: UnsafeMutablePointer<RustBuffer>,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> PublishResultDto in
                guard let uniffiObj = try? FfiConverterCallbackInterfaceActivityPublisherCallback.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return uniffiObj.publishRide(
                     fitBytes: try FfiConverterData.lift(fitBytes),
                     screenshotPng: try FfiConverterOptionData.lift(screenshotPng),
                     summary: try FfiConverterTypeRideSummaryDto_lift(summary)
                )
            }

            
            let writeReturn = { uniffiOutReturn.pointee = FfiConverterTypePublishResultDto_lower($0) }
            uniffiTraitInterfaceCall(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn
            )
        },
        uniffiFree: { (uniffiHandle: UInt64) -> () in
            let result = try? FfiConverterCallbackInterfaceActivityPublisherCallback.handleMap.remove(handle: uniffiHandle)
            if result == nil {
                print("Uniffi callback interface ActivityPublisherCallback: handle missing in uniffiFree")
            }
        }
    )]
}

private func uniffiCallbackInitActivityPublisherCallback() {
    uniffi_velo_ffi_fn_init_callback_vtable_activitypublishercallback(UniffiCallbackInterfaceActivityPublisherCallback.vtable)
}

// FfiConverter protocol for callback interfaces
#if swift(>=5.8)
@_documentation(visibility: private)
#endif
fileprivate struct FfiConverterCallbackInterfaceActivityPublisherCallback {
    fileprivate static let handleMap = UniffiHandleMap<ActivityPublisherCallback>()
